// 安全机制
String? str1=null;   // ?表示可空类型
print(str1);
// 运行时会跳过（因为str1为null，?.会安全跳过）
str1?.startsWith("hello");
// str1="hello world";
// 运行时会报错（!强制解包，若为null则报错）
// str1!.startsWith("hello");
String str2 = str1 ?? "老高";  // ??提供默认值
print(str2);

