// 普通函数定义
int add(int a,int b){
  return a+b;
}
// 可选参数函数（使用{}包裹命名参数，?表示可选）
int add2(int a,{int? b1,int? c1}){
  return a+(b1??0)+(c1??0);  // ??提供默认值
}
// 匿名函数赋值给变量
Function add3 = (int a,int b){
  return a+b;
};
// 箭头函数（表达式函数）
add4()=>print("hello world");

// 函数调用
void main() {
  // 调用普通函数
  int result = add(1,2);
  print(result);  // 3
  // 调用可选参数函数
  int result2 = add2(1,b1:2,c1:3);  // 命名参数需要指定名称
  print(result2);  // 6
  int result3 = add2(1,b1:2);        // 可选参数可以省略
  print(result3);  // 3
  // 调用匿名函数
  int result4 = add3(1,2);
  print(result4);  // 3
  // 调用箭头函数
  add4();  // 输出 hello world
}

class Person{
  String? name = "";
  int? age = 0;
  // 默认构造函数
  // Person(this.name,this.age);
  // 命名构造函数（可以和默认构造函数同时存在）
  Person.createPerson(this.name,this.age);
  // 语法糖构造函数（使用{}包裹命名参数）
  Person({this.name,this.age});
  void study(){
    print("$name在学习");
  }
  // 私有方法（使用_前缀）
  // void _study(){
  //   print("$name在学习");
  // }
}

// 类的实例化和调用
void main() {
  Person p = Person(name:"张三",age:18);  // 使用命名参数构造
  p.study();  // 输出 张三在学习
}

// 继承
class Student extends Person{
  String? id = "";
  @override
  void study(){
    super.study();  // 调用父类方法
  }
}

// 混合（mixin）
// 先定义一个mixin对象
mixin Study{
  String? name = "";
  void study(){
    print("$name在学习");
  }
}
// 使用with实现混合
class Student2 with Study{
  String? id = "";
  @override
  void study(){
    super.study();  // 调用mixin中的方法
  }
}

