// async await就是异步调用的语法糖
void test1() async {
  try{
    await Future(() {
      return "hello world";
    });
    await Future.delayed(Duration(seconds: 2));  // 等待2秒
    print("函数执行");
  }catch(error){
    print(error);
  }
}

// 调用异步函数
void main() {
  test1();  // 2秒后输出 "函数执行"
}

